mapper.select:
/* com.shop.mapper.biz.Mis.selectProductViewList */ SELECT P.ID AS prodId , P.PROD_NM AS prodNm , P.REP_FILE_ID AS repFileId , COALESCE(OI_AGG.totalPaymentAmt, 0) AS totalPaymentAmt , COALESCE(OI_AGG.purchaseCnt, 0) AS purchaseCnt , COALESCE(C_AGG.cartCnt, 0) AS cartCnt , COALESCE(PVL_AGG.pageViewCnt, 0) AS pageViewCnt , ROUND(( COALESCE(OI_AGG.purchaseCnt, 0) * 100 + COALESCE(C_AGG.cartCnt, 0) * 30 + COALESCE(PVL_AGG.pageViewCnt, 0) * 5) / 100.0, 1) AS totalScore FROM TB_PRODUCT P LEFT JOIN ( SELECT OI.PRODUCT_ID , SUM(OI.PAYMENT_AMOUNT) AS totalPaymentAmt , COUNT(OI.ID) AS purchaseCnt FROM TB_ORDER_ITEM OI JOIN TB_ORDER O ON O.ID = OI.ORDER_ID AND O.ORDER_STATUS IN ('O', 'P', 'R', 'S', 'D') AND O.PARTNER_ID = #{partnerId} WHERE OI.CRE_TM >= #{fromDate} AND OI.CRE_TM < #{toDate} GROUP BY OI.PRODUCT_ID ) OI_AGG ON OI_AGG.PRODUCT_ID = P.ID LEFT JOIN ( SELECT PD.PRODUCT_ID , COUNT(C.ID) AS cartCnt FROM TB_PRODUCT_DET PD JOIN TB_CART C ON C.PRODUCT_DET_ID = PD.ID AND C.CRE_TM >= #{fromDate} AND C.CRE_TM < #{toDate} AND C.PARTNER_ID = #{partnerId} WHERE PD.DEL_YN = 'N' GROUP BY PD.PRODUCT_ID ) C_AGG ON C_AGG.PRODUCT_ID = P.ID LEFT JOIN ( SELECT PVL.PRODUCT_ID , COUNT(PVL.ID) AS pageViewCnt FROM TB_PAGE_VIEW_LOG PVL WHERE PVL.IS_BOUNCE = 'N' AND PVL.SCROLL_DEPTH >= 30 AND PVL.CRE_TM >= #{fromDate} AND PVL.CRE_TM < #{toDate} GROUP BY PVL.PRODUCT_ID ) PVL_AGG ON PVL_AGG.PRODUCT_ID = P.ID WHERE P.PARTNER_ID = #{partnerId} AND P.DEL_YN = 'N'
AND (
P.IS_SPRING = 'Y' P.IS_SUMMER = 'Y' P.IS_AUTUMN = 'Y' P.IS_WINTER = 'Y'
)
ORDER BY totalScore DESC

/* com.shop.mapper.biz.Mis.selectSalesStatList */


SELECT TO_CHAR(OI.CRE_TM, 'IYYY') || '-W' || LPAD(TO_CHAR(OI.CRE_TM, 'IW'), 2, '0') AS period
     , SUM(OI.PAYMENT_AMOUNT) AS totalPaymentAmt
     , COUNT(OI.ID)           AS purchaseCnt
FROM TB_ORDER_ITEM OI
JOIN TB_ORDER O ON O.ID = OI.ORDER_ID
               AND O.ORDER_STATUS IN ('O','P','R','S','D')
               AND O.PARTNER_ID = #{partnerId}
WHERE OI.CRE_TM >= #{fromDate}
  AND OI.CRE_TM < #{toDate}
GROUP BY TO_CHAR(OI.CRE_TM, 'IYYY'), TO_CHAR(OI.CRE_TM, 'IW')
ORDER BY TO_CHAR(OI.CRE_TM, 'IYYY'), TO_CHAR(OI.CRE_TM, 'IW')


SELECT TO_CHAR(OI.CRE_TM, 'YYYY-MM') AS period
     , SUM(OI.PAYMENT_AMOUNT) AS totalPaymentAmt
     , COUNT(OI.ID)           AS purchaseCnt
FROM TB_ORDER_ITEM OI
JOIN TB_ORDER O ON O.ID = OI.ORDER_ID
               AND O.ORDER_STATUS IN ('O','P','R','S','D')
               AND O.PARTNER_ID = #{partnerId}
WHERE OI.CRE_TM >= #{fromDate}
  AND OI.CRE_TM < #{toDate}
GROUP BY TO_CHAR(OI.CRE_TM, 'YYYY-MM')
ORDER BY period

/* com.shop.mapper.biz.Mis.selectSalesStatDetailList */ SELECT P.ID AS prodId , P.PROD_NM AS prodNm , P.REP_FILE_ID AS repFileId , COALESCE(OI_AGG.totalPaymentAmt, 0) AS totalPaymentAmt , COALESCE(OI_AGG.purchaseCnt, 0) AS purchaseCnt , COALESCE(C_AGG.cartCnt, 0) AS cartCnt , COALESCE(PVL_AGG.pageViewCnt, 0) AS pageViewCnt , ROUND(( COALESCE(OI_AGG.purchaseCnt, 0) * 100 + COALESCE(C_AGG.cartCnt, 0) * 30 + COALESCE(PVL_AGG.pageViewCnt, 0) * 5) / 100.0, 1) AS totalScore FROM TB_PRODUCT P LEFT JOIN ( SELECT OI.PRODUCT_ID , SUM(OI.PAYMENT_AMOUNT) AS totalPaymentAmt , COUNT(OI.ID) AS purchaseCnt FROM TB_ORDER_ITEM OI JOIN TB_ORDER O ON O.ID = OI.ORDER_ID AND O.ORDER_STATUS IN ('O','P','R','S','D') AND O.PARTNER_ID = #{partnerId}
WHERE TO_CHAR(OI.CRE_TM, 'IYYY') || '-W' || LPAD(TO_CHAR(OI.CRE_TM, 'IW'), 2, '0') = #{period}
WHERE TO_CHAR(OI.CRE_TM, 'YYYY-MM') = #{period}
GROUP BY OI.PRODUCT_ID ) OI_AGG ON OI_AGG.PRODUCT_ID = P.ID LEFT JOIN ( SELECT PD.PRODUCT_ID , COUNT(C.ID) AS cartCnt FROM TB_PRODUCT_DET PD JOIN TB_CART C ON C.PRODUCT_DET_ID = PD.ID AND C.PARTNER_ID = #{partnerId}
WHERE TO_CHAR(C.CRE_TM, 'IYYY') || '-W' || LPAD(TO_CHAR(C.CRE_TM, 'IW'), 2, '0') = #{period}
WHERE TO_CHAR(C.CRE_TM, 'YYYY-MM') = #{period}
AND PD.DEL_YN = 'N' GROUP BY PD.PRODUCT_ID ) C_AGG ON C_AGG.PRODUCT_ID = P.ID LEFT JOIN ( SELECT PVL.PRODUCT_ID , COUNT(PVL.ID) AS pageViewCnt FROM TB_PAGE_VIEW_LOG PVL WHERE PVL.IS_BOUNCE = 'N' AND PVL.SCROLL_DEPTH >= 30
AND TO_CHAR(PVL.CRE_TM, 'IYYY') || '-W' || LPAD(TO_CHAR(PVL.CRE_TM, 'IW'), 2, '0') = #{period}
AND TO_CHAR(PVL.CRE_TM, 'YYYY-MM') = #{period}
GROUP BY PVL.PRODUCT_ID ) PVL_AGG ON PVL_AGG.PRODUCT_ID = P.ID WHERE P.PARTNER_ID = #{partnerId} AND P.DEL_YN = 'N' AND (OI_AGG.purchaseCnt IS NOT NULL OR C_AGG.cartCnt IS NOT NULL OR PVL_AGG.pageViewCnt IS NOT NULL) ORDER BY totalScore DESC
